fn solve(s: String, k: i64) -> String {
    let mut result: Vec<char> = Vec::new();

    for c in s.chars() {
        if c == '*' {
            if !result.is_empty() {
                result.pop();
            }
        } else if c == '#' {
            let mut temp = Vec::new();
            for ch in &result {
                temp.push(*ch);
            }
            for ch in &temp {
                result.push(*ch);
            }
        } else if c == '%' {
            result.reverse();
        } else {
            result.push(c);
        }
    }

    if k < 0 || k >= result.len() as i64 {
        return String::from(".");
    }

    String::from(&result[k as usize..][0..1])
}
